class Solution:
    def magicalString(self, n: int) -> int:
        if n <= 0:
            return 0
        if n <= 3:
            return 1
        s = [1, 2, 2]
        i, cnt = 2, 1
        while len(s) < n:
            if s[i] == 2:
                s.extend([3 - s[-1]] * 2)
            else:
                s.append(3 - s[-1])
            if i < n and s[i] == 1:
                cnt += 1
            i += 1
        return cnt
